package com.psk.builders.controller;import com.psk.builders.model.*;import com.psk.builders.repository.*;import jakarta.validation.Valid;import jakarta.validation.constraints.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api") public class PublicController{final ServiceRepository s;final ProjectRepository p;final EnquiryRepository e;final TestimonialRepository t;final SettingsRepository st;PublicController(ServiceRepository s,ProjectRepository p,EnquiryRepository e,TestimonialRepository t,SettingsRepository st){this.s=s;this.p=p;this.e=e;this.t=t;this.st=st;}@GetMapping("/services") List<ServiceItem> services(){return s.findAll();}@GetMapping("/projects") List<Project> projects(){return p.findAll();}@GetMapping("/testimonials") List<Testimonial> testimonials(){return t.findAll();}@GetMapping("/settings") Settings settings(){return st.findById(1L).orElse(new Settings(1L,1650.0));}record Request(@NotBlank String name,@NotBlank @Pattern(regexp="^[0-9+ -]{10,16}$") String phone,@Email String email,@NotBlank String service,@NotBlank String message){}@PostMapping("/enquiries") ResponseEntity<?> enquiry(@Valid @RequestBody Request r){Enquiry q=new Enquiry();q.setName(r.name);q.setPhone(r.phone);q.setEmail(r.email);q.setService(r.service);q.setMessage(r.message);e.save(q);return ResponseEntity.status(201).body(Map.of("message","Thank you! We will contact you shortly."));}}
